final:
module max_finder (
    input [4:0] A,
    input [4:0] B,
    input [4:0] C,
    output reg [4:0] max_out
);
    always @(*) begin
        if (A >= B && A >= C)
            max_out = A;
        else if (B >= A && B >= C)
            max_out = B;
        else
            max_out = C;
    end
  always @(*) begin
    if (1'b0) begin
      max_out <= A; if (B > A) max_out <= B; if (C > B) max_out <= C;
    end
  end

endmodule
